#pragma mark - function

- (void)whichEndType:(NSString *)animationEndType {
    NSString *type = self.animationAtEnd[animationEndType];
    if ([type isEqual:@"disappear"]) {
        self.handleAnimationEndType = handleAnimationAtEnd_Disappear;
    } else if ([type isEqual:@"loop"]) {
        self.handleAnimationEndType = handleAnimationAtEnd_Loop;
    } else if ([type isEqual:@"pause"]) {
        self.handleAnimationEndType = handleAnimationAtEnd_Pause;
    } else {
        self.handleAnimationEndType = handleAnimationAtEnd_Default;     // 播放完全部暂停
    }
}

- (void)handleEndWithAnimationVC:(WBDynamicAnimationViewController *)animationVC withType:(NSString *)type{
    switch (self.handleAnimationEndType) {
        case handleAnimationAtEnd_Disappear:
            if ([type isEqual:@"main"]) {
                self.animationVC.view.hidden = YES;
            } else {
                [animationVC disappear];
            }
            break;
        case handleAnimationAtEnd_Loop:
            [animationVC loop];
            break;
        case handleAnimationAtEnd_Pause:
            [animationVC pause];
            break;
        default:
            break;
    }
}


- (void)appearA {
    if (self.Amain) {   // 如果A面动画的资源存在
        [self.animationVC updateWithJson:self.Amain];

        [self.animationVC playWithCompletion:^(BOOL animationFinished) {
            if (animationFinished) {
                [self whichEndType:@"A_main"];
                [self handleEndWithAnimationVC:self.animationVC withType:@"main"];

                if (self.Asub) {
                    self.AsubAnimationVC.view.hidden = NO;
                    [self whichEndType:@"A_sub"];
                    [self handleEndWithAnimationVC:self.AsubAnimationVC withType:@"sub"];
                }
                self.closeButton.hidden = NO;

                UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(TappedA:)];
                tapGesture.numberOfTapsRequired = 1;
                [self.animationVC.view addGestureRecognizer:tapGesture];
                if (self.Asub) {
                    [self.AsubAnimationVC.view addGestureRecognizer:tapGesture];
                }
            }
        }];
    } else {
        [self dismissPopupWithCompletion:nil];
    }
}

- (void)TappedA:(UITapGestureRecognizer *)gestureRecognizer {
    [[WBDynamicPopupResUnzip sharedManager] sendClickEvent];    // 点击事件上报
    if (self.isHandlingTappedA) {
        // 同一时间段，只处理最早的一个点击事件
        return;
    }
    self.isHandlingTappedA = YES;

    if([self.linkType integerValue] == linkType_Dismiss || [self.linkType integerValue] == linkType_Default) {
        [self dismissPopupWithCompletion:^{
            self.isHandlingTappedA = NO;
        }];
    } else if ([self.linkType integerValue] == linkType_UrlScheme) {
        if ([self.linkUrl hasPrefix:@"webox:///page"]) {
            __block NSURL *pageUrl = [NSURL URLWithString:self.linkUrl];
            NSString *triggerId = self.richMessageLinkId ?: nil;
            if ([pageUrl.absoluteString isEqualToString:@"webox:///page/vip"] && triggerId) {
                NSURLComponents *components = [NSURLComponents componentsWithString:pageUrl.absoluteString];
                NSMutableArray<NSURLQueryItem *> *queryItems = [components.queryItems mutableCopy] ?: [NSMutableArray new];
                NSURLQueryItem *triggerItem = [NSURLQueryItem queryItemWithName:@"triggerId" value:triggerId];
                [queryItems addObject:triggerItem];
                components.queryItems = queryItems;
                pageUrl = components.URL;
            }
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self dismissPopupWithCompletion:^{
                    [[WBRouteManager sharedManager] performRoute:pageUrl sourceInterface:@"action/popup"];
                    self.isHandlingTappedA = NO;
                }];
            });
        } else if ([self.linkUrl hasPrefix:@"webox:///action"]) {

            NSURL *url = [NSURL URLWithString:self.linkUrl];
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.01 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                if ([self.linkUrl hasPrefix:@"webox:///action/promoReceive"]) {
                    [[NSNotificationCenter defaultCenter] postNotificationName:WBDynamicPromoReceiveNotification object:nil];
                }
                [[WBRouteManager sharedManager] performRoute:url sourceInterface:@"action/popup"];  // 活动弹窗链接跳转路由
                [self dismissPopupWithCompletion:nil];
            });

            self.AsubAnimationVC.view.hidden = YES;
            self.closeButton.hidden = YES;

            /// 💡这里是：谁处理之后需要继续播放动画，就发送 “动画播放继续” 的通知
            [[NSNotificationCenter defaultCenter] addObserverForName:WBAnimationGoOnNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
                if (self.Bmain) {
                    if (self.animationVC.view.hidden) {
                        self.animationVC.view.hidden = NO;
                    }
                    [self.animationVC updateWithJson:self.Bmain];

                    [self.animationVC playWithCompletion:^(BOOL animationFinished) {
                        if (animationFinished) {
                            [self whichEndType:@"B_main"];
                            [self handleEndWithAnimationVC:self.animationVC withType:@"main"];
                            if (self.Bsub) {
                                self.BsubAnimationVC.view.hidden = NO;
                                [self whichEndType:@"B_sub"];
                                [self handleEndWithAnimationVC:self.BsubAnimationVC withType:@"sub"];
                            }
                            self.closeButton.hidden = NO;

                            UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(ifBisTapped:)];
                            tapGesture.numberOfTapsRequired = 1;
                            [self.animationVC.view addGestureRecognizer:tapGesture];
                            if (self.Bsub) {
                                [self.BsubAnimationVC.view addGestureRecognizer:tapGesture];
                            }
                            self.isHandlingTappedA = NO;
                        }
                    }];
                } else {
                    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(SKIP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                        if (self.AcallbackData) {
                            NSString * linkAfterB = self.AcallbackData[@"link"]; // 点击B视图之后的跳转链接
                            NSString * linkTypeAfterB = self.AcallbackData[@"type"]; // 跳转链接类型
                            NSString * dismissAfterBback = self.AcallbackData[@"dismiss"];   // 点击B视图跳转后，B视图消失/恢复

                            [self handleLinkAfterB:linkAfterB linkType:linkTypeAfterB dismiss:dismissAfterBback];
                        }
                    });

                    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(SKIP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                        self.isHandlingTappedA = NO;
                    });
                }
            }];
        }
    } else if ([self.linkType integerValue] == linkType_Safari) {
        [UIApplication.sharedApplication openURL:[NSURL URLWithString:self.linkUrl] options:@{} completionHandler:nil]; // 浏览器跳转网址
        if ([self.dismiss integerValue]) {
            [self dismissPopupWithCompletion:nil];
        }
        self.isHandlingTappedA = NO;
    } else if ([self.linkType integerValue] == linkType_WebView) {
        WBWebViewManager *webVC = [[WBWebViewManager alloc] initWithURL:[NSURL URLWithString:self.linkUrl]];
        webVC.modalPresentationStyle = UIModalPresentationFullScreen;
        UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];
        webVC.webVC.dismissBlock = ^{
            [rootVC dismissViewControllerAnimated:YES completion:nil];
        };
        [self dismissViewControllerAnimated:false completion:^{
            [rootVC presentViewController:webVC animated:true completion:nil];
            self.isHandlingTappedA = NO;
            if (![self.dismiss integerValue]) {
                webVC.webVC.dismissBlock = ^{
                    [rootVC presentViewController:self animated:true completion:nil];
                };
            }
        }];
    } else {
        NSLog(@"这是一个暂时无法识别的link类型");
    }
}


+ (void)handlePromoReceiveWithPromoId:(NSString *)promoId {
    [[WBNetworkManager defaultManager] requestReceiveWithPromoId:promoId callback:^(id _Nullable json, NSError * _Nullable error) {
        if (error) {
            [[NSNotificationCenter defaultCenter] postNotificationName:WBPromoReceiceErrorNotification object:nil];
            NSLog(@"Error receiving promo: %@", error.localizedDescription);
            [SVProgressHUD showErrorWithStatus:error.localizedDescription];
        } else {
            [[NSNotificationCenter defaultCenter] postNotificationName:WBAnimationGoOnNotification object:nil];
            if (json) {
                [[NSNotificationCenter defaultCenter] postNotificationName:WBPromoReceiveSuccessNotification object:nil userInfo:@{@"json": json}];
            }
        }
    }];
}


- (void)ifBisTapped:(UIGestureRecognizer *)gesture {    // B视图被点击
    self.BsubAnimationVC.view.hidden = NO;
    self.closeButton.hidden = YES;

    NSString *linkAfterB = nil;
    NSString *linkTypeAfterB = nil;
    NSString *dismissAfterBback = nil;
    if (self.AcallbackData) {
        linkAfterB = self.AcallbackData[@"link"]; // 点击B视图之后的跳转链接
        linkTypeAfterB = self.AcallbackData[@"type"]; // 跳转链接类型
        dismissAfterBback = self.AcallbackData[@"dismiss"];   // 点击B视图跳转后，B视图消失/恢复
    }
    if (self.rearAnimation) {   // 如果后置动画存在
        [self.rearAnimationVC updateWithJson:self.rearAnimation];

        [self.rearAnimationVC playWithCompletion:^(BOOL animationFinished) {
            if (animationFinished) {
                [self dismissPopupWithCompletion:^{
                    [self handleLinkAfterB:linkAfterB linkType:linkTypeAfterB dismiss:dismissAfterBback];
                }];
            }
        }];
    } else {
        [self dismissPopupWithCompletion:^{
            [self handleLinkAfterB:linkAfterB linkType:linkTypeAfterB dismiss:dismissAfterBback];
        }];
    }
}

- (void)handleLinkAfterB:(NSString *)link linkType:(NSString *)linkType dismiss:(NSString *)dismiss {
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.1 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        UIViewController *rootViewController = [WBAppManager getUIApplicationRootViewController];
        while (rootViewController.presentedViewController) {
            rootViewController = rootViewController.presentedViewController;
        }

        // 如果点击A视图领取优惠券端口有数据返回
        UIAlertController *alertController = [UIAlertController alertControllerWithTitle:@"领取成功" message:@"可至「优惠券」使用" preferredStyle:UIAlertControllerStyleAlert];
        UIAlertAction *cancelAction = [UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
            [[NSNotificationCenter defaultCenter] postNotificationName:WBVipReloadPromoNotification object:nil];
            [alertController dismissViewControllerAnimated:YES completion:nil];
        }];
        UIAlertAction *useAction = [UIAlertAction actionWithTitle:@"去使用" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
            [alertController dismissViewControllerAnimated:YES completion:^{
                // 如果当前在会员中心
                if ([rootViewController isKindOfClass:[WBNavigationController class]]) {
                    WBNavigationController *nav = (WBNavigationController *)rootViewController;
                    if ([nav.viewControllers.firstObject isKindOfClass:[WBVipViewController class]]) {
                        [[NSNotificationCenter defaultCenter] postNotificationName:WBVipReloadPromoNotification object:nil];
                    }
                } else {
                    NSURL *promoReceiveSuccessLink;
                    if (link) {
                        promoReceiveSuccessLink = [NSURL URLWithString:link];
                    } else {
                        promoReceiveSuccessLink = [NSURL URLWithString:@"webox:///page/vip"];
                    }
                    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                        [[WBRouteManager sharedManager] performRoute:promoReceiveSuccessLink sourceInterface:@"promocode/receive"];
                    });
                }
            }];
        }];
        [alertController addAction:cancelAction];
        [alertController addAction:useAction];

        [rootViewController presentViewController:alertController animated:YES completion:nil];
    });
}

