- (void)generateTapButtons {
    NSMutableArray<UIButton *> *buttons = [NSMutableArray array];
    for (NSDictionary *data in self.buttonData) {
        UIButton *button = [UIButton buttonWithType:UIButtonTypeCustom];
        NSString *buttonImageUrl = data[@"image"];
        NSURL *imageUrl = [NSURL URLWithString:buttonImageUrl];
        // 异步加载图片
        NSURLSession *session = [NSURLSession sharedSession];
        [[session dataTaskWithURL:imageUrl completionHandler:^(NSData * _Nullable data, NSURLResponse * _Nullable response, NSError * _Nullable error) {
            if (error) {
                NSLog(@"Failed to load image: %@", error.localizedDescription);
                return;
            }
            UIImage *image = [UIImage imageWithData:data];
            dispatch_async(dispatch_get_main_queue(), ^{
                // 在主线程中设置图片
                [button setBackgroundImage:image forState:UIControlStateNormal];
            });
        }] resume];
        NSInteger index = [buttons count];
        button.tag = index; // 使用 tag 来标识按钮
        [button addTarget:self action:@selector(buttonClicked:) forControlEvents:UIControlEventTouchUpInside];
        [buttons addObject:button];
    }
    self.tapButtons = [buttons copy];  // 保存所有生成的按钮
}


- (void)layoutTapButtons {
    CGFloat totalWidth = ZOOM(301);  // 总宽度
    NSInteger buttonCount = self.tapButtons.count;
    CGFloat buttonHeight = ZOOM(60);

    CGFloat buttonWidth = 0;
    CGFloat spacing = 0;

    // 根据按钮数量动态调整按钮宽度和间距
    switch (buttonCount) {
        case 1: {
            buttonWidth = ZOOM(184);
            spacing = 0;
            break;
        }
        case 2: {
            buttonWidth = ZOOM(124);
            spacing = ZOOM(33);
            break;
        }
        case 3: {
            buttonWidth = ZOOM(84);
            spacing = ZOOM(14);
            break;
        }
        case 4: {
            buttonWidth = ZOOM(64);
            spacing = ZOOM(8);
            break;
        }
        default: {
            buttonWidth = ZOOM(64);
            CGFloat totalButtonWidth = buttonWidth * buttonCount;
            CGFloat sidePadding = ZOOM(10);
            CGFloat remainingSpace = totalWidth - totalButtonWidth - 2 * sidePadding;
            spacing = MAX(remainingSpace / (buttonCount - 1), 0);
            break;
        }
    }

    // 创建一个父容器视图，用于包裹按钮组
    UIView *buttonContainerView = [[UIView alloc] init];
    [self.view addSubview:buttonContainerView];
    [buttonContainerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.imageView.mas_bottom);                 // 按钮距离图片的固定间距
        make.centerX.equalTo(self.imageView.mas_centerX);            // 水平居中对齐
        make.height.mas_equalTo(buttonHeight);                       // 高度固定为按钮高度
        make.width.mas_equalTo(totalWidth);                          // 容器宽度固定为设计宽度
    }];

    // 在容器内布局按钮
    for (NSInteger i = 0; i < buttonCount; i++) {
        UIButton *button = self.tapButtons[i];
        [buttonContainerView addSubview:button];

        [button mas_makeConstraints:^(MASConstraintMaker *make) {
            make.width.mas_equalTo(buttonWidth);
            make.height.mas_equalTo(buttonHeight);
            make.centerY.equalTo(buttonContainerView);  // 垂直居中

            if (buttonCount == 1) {
                make.centerX.equalTo(buttonContainerView.mas_centerX);
            } else if (buttonCount == 2) {
                if (i == 0) {
                    make.left.equalTo(buttonContainerView.mas_left).offset(ZOOM(10));
                } else {
                    make.left.equalTo(self.tapButtons[0].mas_right).offset(spacing);
                }
            } else if (buttonCount == 3) {
                if (i == 0) {
                    make.left.equalTo(buttonContainerView.mas_left).offset(ZOOM(10));
                } else if (i == 1) {
                    make.left.equalTo(self.tapButtons[0].mas_right).offset(spacing);
                } else {
                    make.left.equalTo(self.tapButtons[1].mas_right).offset(spacing);
                }
            } else if (buttonCount == 4) {
                if (i == 0) {
                    make.left.equalTo(buttonContainerView.mas_left).offset(ZOOM(10));
                } else if (i == 1) {
                    make.left.equalTo(self.tapButtons[0].mas_right).offset(spacing);
                } else if (i == 2) {
                    make.left.equalTo(self.tapButtons[1].mas_right).offset(spacing);
                } else {
                    make.left.equalTo(self.tapButtons[2].mas_right).offset(spacing);
                }
            }
        }];
    }
}


