- (instancetype)initWithFrame:(CGRect)frame {
	if (self = [super initWithFrame:frame]) {
		[self addAllSubviews];
		[self addAllConstraints];
		[self addTarget:self action:@selector(handleOnClick) forControlEvents:UIControlEventTouchUpInside];
	}
	return self;
}

- (instancetype)initWithShortcuts:(NSArray *)shortcuts {
	if (self = [self initWithFrame:CGRectZero]) {
		self.shortcuts = shortcuts;
		self.currentIndex = 0;
		self.iconImageView.wb_imageURL = [NSURL URLWithString:self.currentShortcut.iconURL];
		self.titleLabel.text = self.currentShortcut.label;
		[self startRotation];
	}
	return self;
}

- (WBRichMessageLinkModel *)currentShortcut {
	if ([self.shortcuts count] == 0) {
		return nil;
	}
	NSUInteger currentIndex = self.currentIndex % [self.shortcuts count];
	return self.shortcuts[currentIndex];
}

#pragma mark - UI Events

- (void)handleOnClick {
	self.currentShortcut.action = [self getActionBlock:self.currentShortcut];
	if (self.currentShortcut.action) {
		self.currentShortcut.action();
	}
	if (self.currentShortcut.postAction) {
		self.currentShortcut.postAction();
	}
}

#pragma mark - Private

- (void)addAllSubviews {
	[self addSubview:self.iconImageView];
	[self addSubview:self.titleLabel];
}

- (void)addAllConstraints {
	[self.iconImageView mas_makeConstraints:^(MASConstraintMaker *make) {
		make.centerX.top.equalTo(self);
		make.width.height.mas_equalTo(WBRpt(24));
	}];
	[self.titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
		make.centerX.bottom.left.equalTo(self);
	}];
	[self mas_makeConstraints:^(MASConstraintMaker *make) {
		make.width.mas_equalTo(WBRpt(44));
		make.height.mas_equalTo(WBRpt(36));
	}];
}

- (void)startRotation {
	dispatch_async_on_main_queue(^{
		[self rotateToNextShortcutWithDuration:2.0 completion:^(BOOL finished) {
			dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(3.0 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
				[self startRotation];
			});
		}];
	});
}

- (void)rotateToNextShortcutWithDuration:(NSTimeInterval)duration completion:(void (^ __nullable)(BOOL finished))completion {
	self.currentIndex++;
	__weak typeof(self) weakSelf = self;
	[UIView animateWithDuration:duration * 0.5 animations:^{
		weakSelf.iconImageView.layer.transform = CATransform3DMakeRotation(M_PI_2, 0, 1, 0);
		weakSelf.titleLabel.alpha = 0;
	} completion:^(BOOL finished) {
		weakSelf.iconImageView.wb_imageURL = [NSURL URLWithString:self.currentShortcut.iconURL];
		weakSelf.titleLabel.text = self.currentShortcut.label;
		[UIView animateWithDuration:duration * 0.5 animations:^{
			weakSelf.iconImageView.layer.transform = CATransform3DMakeRotation(0, 0, 1, 0);
			weakSelf.titleLabel.alpha = 1.0;
		} completion:completion];
	}];
}

