- (void)vipAndPasswordCheckedLaunchForVApp:(WBVAppModel *)vapp {
    // set the authorized status to FALSE every time the user tap the vapp and try to launch
    vapp.authorized = FALSE;

    if (vapp.isLaunchable) {
        if (self.isSkipActionRequestWhenLaunch) {
            [self launchVappWithVappStatusCheck:vapp];
            return;
        }

        if ([Reachability reachabilityForInternetConnection].currentReachabilityStatus == NotReachable) {
            self.skipVIPCheckWhenLaunch = false;
            [self launchVappWithVappStatusCheck:vapp];
            return;
        }

        [[WBActionRequestManager sharedManager] requestLaunchVappWithVapp:vapp defaultHandler:^(WBBaseActionModel * _Nullable actionModel) {
            BOOL isActionRequestSuccess = actionModel != nil;
            self.skipVIPCheckWhenLaunch = isActionRequestSuccess;
            if (!vapp_is_running()) {
                [self launchVappWithVappStatusCheck:vapp];
            }
        }];
    } else {
        [self presentNotLaunchableUIWithVapp:vapp];
        self.vappLaunching = false;
    }
}

- (void)launchVappWithVappStatusCheck:(WBVAppModel *)vapp {
    oaa_ef_set(vapp.versionInfo.ef);
    NSParameterAssert(vapp.isLaunchable); // 调用前必须保证 vapp 是Launchable
    if (vapp.status == WBVappStatusResourceWaitingDownload) {
        [WBVAppResDownloadManager.sharedManager setVAppDownloadPriorityInQueue:vapp index:0];
        [self authorize:vapp successBlock:^{
            [self handleLaunchResDownloadingVApp:vapp];
        }];
    }
    else if (vapp.status & (WBVappStatusResourceDownloading | WBVappStatusResourceDownloadInterrupted)) {
        [self authorize:vapp successBlock:^{
            [self handleLaunchResDownloadingVApp:vapp];
        }];
    }
    else if (vapp.status & (WBVappStatusResourceDownloadError | WBVappStatusResourceDownloadGiveUp)) {
